diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..9096a0212205 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2263,6 +2263,108 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     return CallInst::Create(F, {Op0, Z});
   }

+  // sub smin/umin(X+1, Y), smin/umin(X, Y) --> select X <(s/u) Y, 1, 0
+  // Also handles swapped operands: smin(Y, X+1), smin(Y, X) and mixed cases
+  // Also handles or disjoint X, 1 as equivalent to X + 1
+  auto foldSubOfMinMaxDiff = [&]() -> Instruction * {
+    auto *MinMax0 = dyn_cast<MinMaxIntrinsic>(Op0);
+    auto *MinMax1 = dyn_cast<MinMaxIntrinsic>(Op1);
+    if (!MinMax0 || !MinMax1)
+      return nullptr;
+    // Both must be the same kind of min (either both smin or both umin)
+    if (MinMax0->getIntrinsicID() != MinMax1->getIntrinsicID())
+      return nullptr;
+    if (MinMax0->getIntrinsicID() != Intrinsic::smin &&
+        MinMax0->getIntrinsicID() != Intrinsic::umin)
+      return nullptr;
+
+    Value *L0 = MinMax0->getLHS();
+    Value *R0 = MinMax0->getRHS();
+    Value *L1 = MinMax1->getLHS();
+    Value *R1 = MinMax1->getRHS();
+
+    // Find the shared operand (Y) and the pair of operands (X, X+1)
+    // The shared operand must be the same in both min calls
+    Value *Shared = nullptr;
+    Value *X = nullptr;    // The base value
+    Value *XPlus1 = nullptr; // The value X + 1
+    
+    // Check if RHS operands are the same (original case)
+    if (R0 == R1) {
+      Shared = R0;
+      XPlus1 = L0;
+      X = L1;
+    }
+    // Check if LHS operands are the same
+    else if (L0 == L1) {
+      Shared = L0;
+      XPlus1 = R0;
+      X = R1;
+    }
+    // Check if LHS of first == RHS of second
+    else if (L0 == R1) {
+      Shared = L0;
+      XPlus1 = R0;
+      X = L1;
+    }
+    // Check if RHS of first == LHS of second
+    else if (R0 == L1) {
+      Shared = R0;
+      XPlus1 = L0;
+      X = R1;
+    }
+    else {
+      return nullptr;
+    }
+
+    // Check that XPlus1 == X + 1 or X | 1 (disjoint)
+    // For signed min, we need nsw flag on add
+    // For unsigned min, we need nuw flag on add
+    // For or disjoint X, 1, it's safe when X is even (LSB is 0)
+    const APInt *C;
+    Value *AddVal = nullptr;
+    bool HasCorrectWrap = false;
+    
+    if (match(XPlus1, m_c_Add(m_Specific(X), m_APInt(C)))) {
+      if (!C->isOne())
+        return nullptr;
+      AddVal = XPlus1;
+      auto *Add = dyn_cast<BinaryOperator>(AddVal);
+      if (!Add)
+        return nullptr;
+      if (MinMax0->isSigned())
+        HasCorrectWrap = Add->hasNoSignedWrap();
+      else
+        HasCorrectWrap = Add->hasNoUnsignedWrap();
+    } else if (match(XPlus1, m_c_Or(m_Specific(X), m_One()))) {
+      // Check for "or disjoint X, 1" pattern
+      auto *Or = dyn_cast<BinaryOperator>(XPlus1);
+      if (!Or || !Or->isDisjoint())
+        return nullptr;
+      // X | 1 is safe when X is even (LSB is 0)
+      // We need to check if X is known to be even
+      KnownBits Known = SQ.getKnownBits(X);
+      if (!Known.Zero.getBoolValue(0))
+        return nullptr; // LSB might be 1, not safe
+      HasCorrectWrap = true;
+      AddVal = XPlus1; // Use Or as the increment operation
+    } else {
+      return nullptr;
+    }
+    
+    if (!HasCorrectWrap)
+      return nullptr;
+
+    // sub(smin/umin(X+1, Y), smin/umin(X, Y)) --> select X < Y, 1, 0
+    ICmpInst::Predicate Pred = MinMax0->isSigned() ? ICmpInst::ICMP_SLT
+                                                   : ICmpInst::ICMP_ULT;
+    Value *Cmp = Builder.CreateICmp(Pred, X, Shared);
+    return SelectInst::Create(Cmp, ConstantInt::get(Ty, 1),
+                              ConstantInt::get(Ty, 0));
+  };
+  if (Instruction *R = foldSubOfMinMaxDiff())
+    return R;
+
   return nullptr;
 }

